-- Original PG function: ~/Desktop/article_selection_list_v2.sql

INSERT OR REPLACE INTO dataviews (id, app_id, display_name, contract, dimensions, columns, sort, backend_workflow, cascading_filters)
VALUES (
  'article_selection_v2',
  'bealls-inventory-smart-app',
  'Article Selection v2',

  -- CONTRACT
  json('{"engine":"duckdb","cache_strategy":"on_demand","refresh_mode":"full","read_query":"SELECT l0_name, l1_name, l2_name, l3_name, l4_name, l5_name, style_color_description, article, ph_code, product_description, sizes, upc, product_life_cycle, article_status_tag, brand, channel, reserve_quantity, oh, oo, it, pack_type_id, oh_map, rq_map, allocated_units, net_available_inventory, au_map, product_profiles, last_allocated, dcs, store_groups, mapped_stores_count, mapped_stores, aps, min_stock, max_stock, min_stock_validator, max_stock_validator, wos, avg_max_mod, min_woc, max_woc, lw_units, lw_margin, lw_revenue, price, discount, in_stock_perc, beginning_available_to_allocate_eaches, beginning_available_to_allocate_packs, allocation_rules, min_type FROM read_parquet(''{PARQUET_HOME}/article_selection_v2/**/*.parquet'', hive_partitioning=true) {where_clause} {order_clause} LIMIT {limit} OFFSET {offset}","operations":["list","filter","sort","search","paginate","download"]}'),

  -- DIMENSIONS
  json('["product","store"]'),

  -- COLUMNS
  json('[{"name":"l0_name","type":"varchar","display_name":"Division","visible":false,"sortable":true,"searchable":false,"group":"hierarchy"},{"name":"l1_name","type":"varchar","display_name":"Department","visible":true,"sortable":true,"searchable":true,"group":"hierarchy"},{"name":"l2_name","type":"varchar","display_name":"Class","visible":true,"sortable":true,"searchable":true,"group":"hierarchy"},{"name":"l3_name","type":"varchar","display_name":"Sub-Class","visible":true,"sortable":true,"searchable":true,"group":"hierarchy"},{"name":"l4_name","type":"varchar","display_name":"Style","visible":true,"sortable":true,"searchable":true,"group":"hierarchy"},{"name":"l5_name","type":"varchar","display_name":"Color","visible":true,"sortable":true,"searchable":true,"group":"hierarchy"},{"name":"style_color_description","type":"varchar","display_name":"Style Color Description","visible":true,"sortable":true,"searchable":true,"group":"product"},{"name":"article","type":"varchar","display_name":"Article","visible":true,"sortable":true,"searchable":true,"group":"product"},{"name":"ph_code","type":"varchar","display_name":"PH Code","visible":true,"sortable":true,"searchable":true,"group":"product"},{"name":"product_description","type":"varchar","display_name":"Product Description","visible":true,"sortable":true,"searchable":true,"group":"product"},{"name":"sizes","type":"json","display_name":"Sizes","visible":true,"sortable":false,"searchable":false,"group":"product"},{"name":"upc","type":"json","display_name":"UPC","visible":true,"sortable":false,"searchable":false,"group":"product"},{"name":"product_life_cycle","type":"varchar","display_name":"Product Lifecycle","visible":true,"sortable":true,"searchable":false,"group":"product"},{"name":"article_status_tag","type":"varchar","display_name":"Article Status","visible":true,"sortable":true,"searchable":false,"group":"product"},{"name":"brand","type":"varchar","display_name":"Brand","visible":true,"sortable":true,"searchable":true,"group":"product"},{"name":"channel","type":"json","display_name":"Channel","visible":true,"sortable":false,"searchable":false,"group":"product"},{"name":"reserve_quantity","type":"integer","display_name":"Reserve Qty","visible":true,"sortable":true,"searchable":false,"group":"inventory","default":0},{"name":"oh","type":"integer","display_name":"On Hand","visible":true,"sortable":true,"searchable":false,"group":"inventory","default":0},{"name":"oo","type":"integer","display_name":"On Order","visible":true,"sortable":true,"searchable":false,"group":"inventory","default":0},{"name":"it","type":"integer","display_name":"In Transit","visible":true,"sortable":true,"searchable":false,"group":"inventory","default":0},{"name":"pack_type_id","type":"varchar","display_name":"Pack Type","visible":false,"sortable":false,"searchable":false,"group":"inventory"},{"name":"oh_map","type":"json","display_name":"OH by Size/DC","visible":true,"sortable":false,"searchable":false,"group":"inventory_detail"},{"name":"rq_map","type":"json","display_name":"Reserve by Size/DC","visible":true,"sortable":false,"searchable":false,"group":"inventory_detail"},{"name":"allocated_units","type":"integer","display_name":"Allocated Units","visible":true,"sortable":true,"searchable":false,"group":"inventory","default":0},{"name":"net_available_inventory","type":"integer","display_name":"Net Available","visible":true,"sortable":true,"searchable":false,"group":"inventory","default":0},{"name":"au_map","type":"json","display_name":"Allocated by Size/DC","visible":true,"sortable":false,"searchable":false,"group":"inventory_detail"},{"name":"product_profiles","type":"json","display_name":"Product Profiles","visible":true,"sortable":false,"searchable":false,"group":"config"},{"name":"last_allocated","type":"varchar","display_name":"Last Allocated","visible":true,"sortable":true,"searchable":false,"group":"config"},{"name":"dcs","type":"json","display_name":"Distribution Centres","visible":true,"sortable":false,"searchable":false,"group":"config"},{"name":"store_groups","type":"json","display_name":"Store Groups","visible":true,"sortable":false,"searchable":false,"group":"config"},{"name":"mapped_stores_count","type":"integer","display_name":"Mapped Stores","visible":true,"sortable":true,"searchable":false,"group":"constraints","default":0},{"name":"mapped_stores","type":"json","display_name":"Mapped Store List","visible":false,"sortable":false,"searchable":false,"group":"constraints"},{"name":"aps","type":"decimal","display_name":"APS","visible":true,"sortable":true,"searchable":false,"group":"constraints"},{"name":"min_stock","type":"integer","display_name":"Min Stock","visible":true,"sortable":true,"searchable":false,"group":"constraints","default":0},{"name":"max_stock","type":"integer","display_name":"Max Stock","visible":true,"sortable":true,"searchable":false,"group":"constraints","default":0},{"name":"min_stock_validator","type":"integer","display_name":"Min Stock Validator","visible":true,"sortable":true,"searchable":false,"group":"constraints","default":0},{"name":"max_stock_validator","type":"integer","display_name":"Max Stock Validator","visible":true,"sortable":true,"searchable":false,"group":"constraints","default":0},{"name":"wos","type":"integer","display_name":"WOS","visible":true,"sortable":true,"searchable":false,"group":"woc","default":0},{"name":"avg_max_mod","type":"integer","display_name":"Avg Max MOD","visible":true,"sortable":true,"searchable":false,"group":"woc","default":0},{"name":"min_woc","type":"integer","display_name":"Min WOC","visible":true,"sortable":true,"searchable":false,"group":"woc","default":0},{"name":"max_woc","type":"integer","display_name":"Max WOC","visible":true,"sortable":true,"searchable":false,"group":"woc","default":0},{"name":"lw_units","type":"integer","display_name":"LW Units","visible":true,"sortable":true,"searchable":false,"group":"metrics","default":0},{"name":"lw_margin","type":"integer","display_name":"LW Margin","visible":true,"sortable":true,"searchable":false,"group":"metrics","default":0},{"name":"lw_revenue","type":"integer","display_name":"LW Revenue","visible":true,"sortable":true,"searchable":false,"group":"metrics","default":0},{"name":"price","type":"decimal","display_name":"Price","visible":true,"sortable":true,"searchable":false,"group":"metrics"},{"name":"discount","type":"decimal","display_name":"Discount","visible":true,"sortable":true,"searchable":false,"group":"metrics"},{"name":"in_stock_perc","type":"decimal","display_name":"In Stock %","visible":true,"sortable":true,"searchable":false,"group":"metrics"},{"name":"dc_instock","type":"decimal","display_name":"DC In Stock %","visible":true,"sortable":true,"searchable":false,"group":"metrics"},{"name":"beginning_available_to_allocate_eaches","type":"integer","display_name":"BATA Eaches","visible":true,"sortable":true,"searchable":false,"group":"allocation","default":0},{"name":"beginning_available_to_allocate_packs","type":"integer","display_name":"BATA Packs","visible":true,"sortable":true,"searchable":false,"group":"allocation","default":0},{"name":"allocation_rules","type":"json","display_name":"Allocation Rules","visible":true,"sortable":false,"searchable":false,"group":"allocation"},{"name":"min_type","type":"varchar","display_name":"Min Type","visible":true,"sortable":true,"searchable":false,"group":"allocation"}]'),

  -- SORT
  json('[{"column":"article","direction":"asc"}]'),

  -- BACKEND_WORKFLOW
  json('{"source": {"type": "pg_multi_table", "connection_ref": "bealls_pg", "description": "Replaces inventory_smart.article_selection_list_v2() \u2014 all logic moved to server-side pipeline (Rust + DuckDB). RCL resolution via dedicated gRPC service (rcl-resolution-service). Source tables extracted from PG, joins + aggregations done in DuckDB."}, "parquet": {"path": "article_selection_v2", "partition_columns": ["l1_name"], "refresh_mode": "full", "write_mode": "parallel"}, "pipeline": [{"id": "extract_ph_master", "type": "pg_extract", "label": "Extract ph_master (full product hierarchy)", "config": {"depends_on": [], "output_path": "article_selection_v2/ph_master", "query": "SELECT ph_code, channel, article, product_codes, l0_name, l1_name, l2_name, l3_name, l4_name, l5_name, style_color_description, product_description, sizes, product_lifecycle, article_status_tag, brand, product_code_size_map::text AS product_code_size_map FROM inventory_smart.ph_master"}, "children": []}, {"id": "extract_aid", "type": "pg_extract", "label": "Extract article_inventory_dashboard", "config": {"depends_on": [], "output_path": "article_selection_v2/aid", "query": "SELECT article, store_code, oh, oo, it, lw_units, lw_margin, lw_revenue, msrp, discount, in_stock FROM inventory_smart.article_inventory_dashboard"}, "children": []}, {"id": "extract_sku_dc_available", "type": "pg_extract", "label": "Extract sku_dc_available_units", "config": {"depends_on": [], "output_path": "article_selection_v2/sku_dc_available", "query": "SELECT product_code, dc_code, size, article, COALESCE(oh,0) AS oh, COALESCE(oo,0) AS oo, COALESCE(it,0) AS it FROM inventory_smart.sku_dc_available_units"}, "children": []}, {"id": "extract_sku_dc_reserved", "type": "pg_extract", "label": "Extract sku_dc_reserved_units", "config": {"depends_on": [], "output_path": "article_selection_v2/sku_dc_reserved", "query": "SELECT product_code, dc_code, size, article, COALESCE(quantity,0) AS quantity FROM inventory_smart.sku_dc_reserved_units"}, "children": []}, {"id": "extract_sku_dc_allocated", "type": "pg_extract", "label": "Extract sku_dc_allocated_units", "config": {"depends_on": [], "output_path": "article_selection_v2/sku_dc_allocated", "query": "SELECT article, dc_code, size, updated_at, COALESCE(quantity,0) AS quantity FROM inventory_smart.sku_dc_allocated_units('''', ''{}'')"}, "children": []}, {"id": "extract_dc_pack_inv", "type": "pg_extract", "label": "Extract dc_pack_inventory + configuration (joined)", "config": {"depends_on": [], "output_path": "article_selection_v2/dc_pack", "query": "SELECT dpi.dc_code, dpi.article, CASE WHEN dpi.pack_type = ''eaches'' THEN COALESCE(dpc.units_in_pack,1) * COALESCE(dpi.oh_pack_qty,0) ELSE 0 END AS eaches, CASE WHEN dpi.pack_type = ''packs'' THEN COALESCE(dpc.units_in_pack,1) * COALESCE(dpi.oh_pack_qty,0) ELSE 0 END AS packs FROM inventory_smart.dc_pack_inventory dpi JOIN inventory_smart.dc_pack_configuration dpc ON dpi.pack_type_id = dpc.pack_type_id AND dpi.article = dpc.article AND dpi.pack_type = dpc.pack_type"}, "children": []}, {"id": "extract_last_alloc", "type": "pg_extract", "label": "Extract last_allocated_details", "config": {"depends_on": [], "output_path": "article_selection_v2/last_allocated", "query": "SELECT article, updated_at AS allocated_time FROM inventory_smart.last_allocated_details"}, "children": []}, {"id": "extract_woc_master", "type": "pg_extract", "label": "Extract woc_master", "config": {"depends_on": [], "output_path": "article_selection_v2/woc_master", "query": "SELECT l4_name, store_code, woc, max_mod FROM inventory_smart.woc_master WHERE woc IS NOT NULL"}, "children": []}, {"id": "extract_product_profiles", "type": "pg_extract", "label": "Extract product_profile_master", "config": {"depends_on": [], "output_path": "article_selection_v2/product_profile_master", "query": "SELECT ph_code, pp_code, name, special_classification FROM inventory_smart.product_profile_master"}, "children": []}, {"id": "extract_pp_user_mapping_size", "type": "pg_extract", "label": "Extract product_profile_user_mapping_size", "config": {"depends_on": [], "output_path": "article_selection_v2/pp_user_mapping_size", "query": "SELECT pp_code, size FROM inventory_smart.product_profile_user_mapping_size"}, "children": []}, {"id": "extract_article_instock", "type": "pg_extract", "label": "Extract article_instock", "config": {"depends_on": [], "output_path": "article_selection_v2/article_instock", "query": "SELECT article, in_stock_count, total_count, dc_instock_count, dc_instock_total_count FROM inventory_smart.article_instock"}, "children": []}, {"id": "extract_dc_store_policy_rules", "type": "pg_extract", "label": "Extract dc_store_policy_user_rule", "config": {"depends_on": [], "output_path": "article_selection_v2/dc_store_policy_user_rule", "query": "SELECT rule_code, rule_type, values FROM inventory_smart.dc_store_policy_user_rule"}, "children": []}, {"id": "extract_product_dc", "type": "pg_extract", "label": "Extract product_mapping_product_dc (active)", "config": {"depends_on": [], "output_path": "article_selection_v2/product_mapping_product_dc", "query": "SELECT product_code, dc_code FROM global.product_mapping_product_dc WHERE is_active = true"}, "children": []}, {"id": "extract_dist_centres", "type": "pg_extract", "label": "Extract distribution_centres (active, not deleted)", "config": {"depends_on": [], "output_path": "article_selection_v2/distribution_centres", "query": "SELECT dc_code, name FROM global.distribution_centres WHERE is_active = true AND is_deleted = false"}, "children": []}, {"id": "extract_store_dc", "type": "pg_extract", "label": "Extract product_mapping_store_dc (active)", "config": {"depends_on": [], "output_path": "article_selection_v2/product_mapping_store_dc", "query": "SELECT store_code, dc_code FROM global.product_mapping_store_dc WHERE is_active = true"}, "children": []}, {"id": "extract_store_groups", "type": "pg_extract", "label": "Extract store_groups (not deleted)", "config": {"depends_on": [], "output_path": "article_selection_v2/store_groups", "query": "SELECT sg_code, name, is_deleted FROM global.store_groups WHERE is_deleted = false"}, "children": []}, {"id": "extract_sg_mapping", "type": "pg_extract", "label": "Extract store_groups_mapping", "config": {"depends_on": [], "output_path": "article_selection_v2/store_groups_mapping", "query": "SELECT sg_code, store_code FROM global.store_groups_mapping"}, "children": []}, {"id": "extract_paf", "type": "pg_extract", "label": "Extract product_attributes_filter", "config": {"depends_on": [], "output_path": "product_attributes_filter", "query": "SELECT article, product_code, l0_name, l1_name, l2_name, l3_name, l4_name, l5_name, active FROM global.product_attributes_filter WHERE active = true", "shared": true}, "children": []}, {"id": "extract_psaf", "type": "pg_extract", "label": "Extract product_store_attributes_filter", "config": {"depends_on": [], "output_path": "article_selection_v2/psaf", "query": "SELECT store_code, psa_code, l0_name, l1_name FROM global.product_store_attributes_filter"}, "children": []}, {"id": "extract_rcl_master", "type": "pg_extract", "label": "Extract rcl_master (for specificity ranking)", "config": {"depends_on": [], "output_path": "article_selection_v2/rcl_master", "query": "SELECT rcl_code, priority, level FROM global.rcl_master"}, "children": []}, {"id": "rcl_dc_store_policy", "type": "grpc_call", "label": "RCL: Resolve DC store policy for all products", "config": {"depends_on": ["load_ph"], "service": "rcl-resolution", "method": "ResolveDcStorePolicy", "input_query": "SELECT DISTINCT unnest(string_split(product_codes, '','')) AS product_code FROM ph_master", "output_path": "article_selection_v2/rcl_dc_store_policy", "rule_type_code": 10003, "effective_date": ""}, "children": []}, {"id": "rcl_psm_resolve", "type": "grpc_call", "label": "RCL: Resolve product-store mapping (PSM)", "config": {"depends_on": ["rcl_dc_store_policy", "load_sg_mapping", "load_psaf", "load_ph"], "service": "rcl-resolution", "method": "ResolvePsm", "input_query": "SELECT phu.product_code, sgm.store_code, psaf.psa_code FROM (SELECT ph_code, json_extract_string(pcsm.value, ''$.product_code'') AS product_code FROM ph_master, LATERAL (SELECT unnest(from_json(product_code_size_map::JSON, ''[\"json\"]'')) AS value) pcsm) phu JOIN (SELECT ph_code, COALESCE(pcms.default_store_group, 504) AS default_sg_code FROM ph_master LEFT JOIN (SELECT ph_code, unnest(default_store_groups) AS default_store_group FROM _grpc_dc_policy) pcms USING (ph_code)) pcm USING (ph_code) JOIN store_groups sg ON pcm.default_sg_code = sg.sg_code AND NOT sg.is_deleted JOIN store_groups_mapping sgm ON sgm.sg_code = sg.sg_code JOIN psaf ON sgm.store_code = psaf.store_code GROUP BY 1, 2, 3", "output_path": "article_selection_v2/rcl_psm_resolved", "rule_type_code": 101, "effective_date": ""}, "children": []}, {"id": "rcl_constraint_resolve", "type": "grpc_call", "label": "RCL: Resolve constraints (APS, WOS, min/max stock)", "config": {"depends_on": ["rcl_psm_resolve", "load_paf", "load_psaf"], "service": "rcl-resolution", "method": "ResolveConstraints", "input_query": "SELECT psm.product_code, psm.store_code, psaf.psa_code, paf.article FROM rcl_psm_filtered psm JOIN paf USING (product_code) JOIN psaf ON paf.l0_name = psaf.l0_name AND paf.l1_name = psaf.l1_name AND psm.store_code = psaf.store_code", "output_path": "article_selection_v2/rcl_constraints", "rule_type_code": 170, "effective_date": ""}, "children": []}, {"id": "load_ph", "type": "duckdb_table", "label": "Load ph_master", "config": {"depends_on": ["extract_ph_master"], "source_parquet": "article_selection_v2/ph_master/**/*.parquet", "table_name": "ph_master"}, "children": []}, {"id": "load_aid", "type": "duckdb_table", "label": "Load AID", "config": {"depends_on": ["extract_aid"], "source_parquet": "article_selection_v2/aid/**/*.parquet", "table_name": "aid"}, "children": []}, {"id": "load_sku_avail", "type": "duckdb_table", "label": "Load SKU DC available", "config": {"depends_on": ["extract_sku_dc_available"], "source_parquet": "article_selection_v2/sku_dc_available/**/*.parquet", "table_name": "sku_dc_available"}, "children": []}, {"id": "load_sku_reserved", "type": "duckdb_table", "label": "Load SKU DC reserved", "config": {"depends_on": ["extract_sku_dc_reserved"], "source_parquet": "article_selection_v2/sku_dc_reserved/**/*.parquet", "table_name": "sku_dc_reserved"}, "children": []}, {"id": "load_sku_alloc", "type": "duckdb_table", "label": "Load SKU DC allocated", "config": {"depends_on": ["extract_sku_dc_allocated"], "source_parquet": "article_selection_v2/sku_dc_allocated/**/*.parquet", "table_name": "sku_dc_allocated"}, "children": []}, {"id": "load_dc_pack", "type": "duckdb_table", "label": "Load DC pack inventory", "config": {"depends_on": ["extract_dc_pack_inv"], "source_parquet": "article_selection_v2/dc_pack/**/*.parquet", "table_name": "dc_pack"}, "children": []}, {"id": "load_last_alloc", "type": "duckdb_table", "label": "Load last allocated", "config": {"depends_on": ["extract_last_alloc"], "source_parquet": "article_selection_v2/last_allocated/**/*.parquet", "table_name": "last_allocated"}, "children": []}, {"id": "load_woc", "type": "duckdb_table", "label": "Load WOC master", "config": {"depends_on": ["extract_woc_master"], "source_parquet": "article_selection_v2/woc_master/**/*.parquet", "table_name": "woc_master"}, "children": []}, {"id": "load_pp_master", "type": "duckdb_table", "label": "Load product profiles", "config": {"depends_on": ["extract_product_profiles"], "source_parquet": "article_selection_v2/product_profile_master/**/*.parquet", "table_name": "product_profile_master"}, "children": []}, {"id": "load_pp_size", "type": "duckdb_table", "label": "Load PP user mapping size", "config": {"depends_on": ["extract_pp_user_mapping_size"], "source_parquet": "article_selection_v2/pp_user_mapping_size/**/*.parquet", "table_name": "pp_user_mapping_size"}, "children": []}, {"id": "load_instock", "type": "duckdb_table", "label": "Load article_instock", "config": {"depends_on": ["extract_article_instock"], "source_parquet": "article_selection_v2/article_instock/**/*.parquet", "table_name": "article_instock"}, "children": []}, {"id": "load_ds_rules", "type": "duckdb_table", "label": "Load DC store policy rules", "config": {"depends_on": ["extract_dc_store_policy_rules"], "source_parquet": "article_selection_v2/dc_store_policy_user_rule/**/*.parquet", "table_name": "dc_store_policy_user_rule"}, "children": []}, {"id": "load_prod_dc", "type": "duckdb_table", "label": "Load product-DC mapping", "config": {"depends_on": ["extract_product_dc"], "source_parquet": "article_selection_v2/product_mapping_product_dc/**/*.parquet", "table_name": "product_mapping_product_dc"}, "children": []}, {"id": "load_dist_centres", "type": "duckdb_table", "label": "Load distribution centres", "config": {"depends_on": ["extract_dist_centres"], "source_parquet": "article_selection_v2/distribution_centres/**/*.parquet", "table_name": "distribution_centres"}, "children": []}, {"id": "load_store_dc", "type": "duckdb_table", "label": "Load store-DC mapping", "config": {"depends_on": ["extract_store_dc"], "source_parquet": "article_selection_v2/product_mapping_store_dc/**/*.parquet", "table_name": "product_mapping_store_dc"}, "children": []}, {"id": "load_sg", "type": "duckdb_table", "label": "Load store groups", "config": {"depends_on": ["extract_store_groups"], "source_parquet": "article_selection_v2/store_groups/**/*.parquet", "table_name": "store_groups"}, "children": []}, {"id": "load_sg_mapping", "type": "duckdb_table", "label": "Load SG mapping", "config": {"depends_on": ["extract_sg_mapping"], "source_parquet": "article_selection_v2/store_groups_mapping/**/*.parquet", "table_name": "store_groups_mapping"}, "children": []}, {"id": "load_paf", "type": "duckdb_table", "label": "Load product attributes filter", "config": {"depends_on": ["extract_paf"], "source_parquet": "product_attributes_filter/**/*.parquet", "table_name": "paf"}, "children": []}, {"id": "load_psaf", "type": "duckdb_table", "label": "Load product-store attr filter", "config": {"depends_on": ["extract_psaf"], "source_parquet": "article_selection_v2/psaf/**/*.parquet", "table_name": "psaf"}, "children": []}, {"id": "load_rcl_master", "type": "duckdb_table", "label": "Load RCL master", "config": {"depends_on": ["extract_rcl_master"], "source_parquet": "article_selection_v2/rcl_master/**/*.parquet", "table_name": "rcl_master"}, "children": []}, {"id": "load_rcl_policy", "type": "duckdb_table", "label": "Load RCL DC store policy", "config": {"depends_on": ["rcl_dc_store_policy"], "source_parquet": "article_selection_v2/rcl_dc_store_policy/**/*.parquet", "table_name": "rcl_dc_store_policy"}, "children": []}, {"id": "load_rcl_psm", "type": "duckdb_table", "label": "Load RCL PSM resolved", "config": {"depends_on": ["rcl_psm_resolve"], "source_parquet": "article_selection_v2/rcl_psm_resolved/**/*.parquet", "table_name": "rcl_psm_resolved"}, "children": []}, {"id": "load_rcl_constr", "type": "duckdb_table", "label": "Load RCL constraints", "config": {"depends_on": ["rcl_constraint_resolve"], "source_parquet": "article_selection_v2/rcl_constraints/**/*.parquet", "table_name": "rcl_constraints"}, "children": []}, {"id": "materialize_ph_config", "type": "duckdb_query", "label": "Build ph_configuration_mapping (article-level RCL policy)", "config": {"depends_on": ["load_ph", "load_rcl_policy"], "query": "CREATE OR REPLACE TABLE ph_configuration_mapping AS SELECT array_agg(rd.product_code) AS product_codes, max(rd.default_store_groups) AS default_store_groups, max(rd.default_product_profile) AS default_product_profile, max(rd.dc_store_rule) AS dc_store_rule, psaf.article, psaf.ph_code FROM rcl_dc_store_policy rd JOIN (SELECT unnest(string_split(product_codes, '','')) AS product_code, article, ph_code FROM ph_master) psaf USING (product_code) GROUP BY psaf.article, psaf.ph_code"}, "children": []}, {"id": "materialize_psm_filtered", "type": "duckdb_query", "label": "Filter RCL PSM by specificity (priority + level depth)", "config": {"depends_on": ["load_rcl_psm", "load_rcl_master"], "query": "CREATE OR REPLACE TABLE rcl_psm_filtered AS SELECT product_code, store_code, rcl_code, is_active FROM (SELECT psm.*, RANK() OVER (PARTITION BY psm.product_code ORDER BY rm.priority ASC, array_length(rm.level, 1) DESC) AS rnk FROM rcl_psm_resolved psm JOIN rcl_master rm ON psm.rcl_code = rm.rcl_code) ranked WHERE rnk = 1"}, "children": []}, {"id": "materialize", "type": "duckdb_query", "label": "Materialize article_selection_v2 (full assembly)", "config": {"depends_on": ["load_ph", "load_aid", "load_sku_avail", "load_sku_reserved", "load_sku_alloc", "load_dc_pack", "load_last_alloc", "load_woc", "load_pp_master", "load_pp_size", "load_instock", "load_ds_rules", "load_prod_dc", "load_dist_centres", "load_store_dc", "load_sg", "load_sg_mapping", "load_paf", "load_psaf", "materialize_ph_config", "materialize_psm_filtered", "load_rcl_constr"], "query": "CREATE OR REPLACE TABLE article_selection_v2 AS WITH ph AS (SELECT pm.ph_code, pm.channel, pm.article, pm.product_codes, pm.l0_name, pm.l1_name, pm.l2_name, pm.l3_name, pm.l4_name, pm.l5_name, pm.style_color_description, pm.product_description, pm.sizes, pm.product_lifecycle, pm.article_status_tag, pm.brand, pm.product_code_size_map FROM ph_master pm SEMI JOIN (SELECT DISTINCT article FROM aid) a ON pm.article = a.article), ph_unnested AS (SELECT ph.ph_code, ph.channel, ph.article, ph.product_codes, json_extract_string(pcsm.value, ''$.product_code'') AS product_code, json_extract_string(pcsm.value, ''$.size'') AS size FROM ph, LATERAL (SELECT unnest(from_json(ph.product_code_size_map::JSON, ''[\"json\"]'')) AS value) pcsm), product_dc_map AS (SELECT phu.ph_code, phu.channel, phu.article, phu.product_code, phu.size, pmpd.dc_code FROM ph_unnested phu JOIN product_mapping_product_dc pmpd ON pmpd.product_code = phu.product_code JOIN distribution_centres gdc ON gdc.dc_code = pmpd.dc_code), product_store_dc_mapping AS (SELECT DISTINCT pmps.product_code, pmps.store_code, pdc.ph_code, pdc.article, pmsd.dc_code, pdc.size FROM ph JOIN rcl_psm_filtered pmps ON pmps.product_code = ANY(string_split(ph.product_codes, '','')) JOIN product_dc_map pdc ON pdc.ph_code = ph.ph_code JOIN product_mapping_store_dc pmsd ON pmsd.store_code = pmps.store_code AND pmsd.dc_code = pdc.dc_code), psm_ph_article_dc AS (SELECT DISTINCT ph_code, article, dc_code FROM product_store_dc_mapping), psm_ph_article_store AS (SELECT DISTINCT ph_code, article, store_code FROM product_store_dc_mapping), psm_ph_store AS (SELECT DISTINCT ph_code, store_code, product_code FROM product_store_dc_mapping), product_dc_map_after_store AS (SELECT DISTINCT ph_code, product_code, size, article, dc_code FROM product_store_dc_mapping), txs_metrics AS (SELECT ph.ph_code, CAST(ROUND(SUM(COALESCE(CAST(a.lw_units AS INTEGER),0))) AS INTEGER) AS lw_units, CAST(ROUND(SUM(COALESCE(CAST(a.lw_margin AS INTEGER),0))) AS INTEGER) AS lw_margin, CAST(ROUND(SUM(COALESCE(CAST(a.lw_revenue AS INTEGER),0))) AS INTEGER) AS lw_revenue, ROUND(COALESCE(SUM(CAST(a.lw_revenue AS DECIMAL))/NULLIF(SUM(CAST(a.lw_units AS DECIMAL)),0),0)::DECIMAL,2) AS price, ROUND(COALESCE(SUM(CAST(a.msrp AS DECIMAL)*CAST(a.discount AS DECIMAL))/NULLIF(SUM(CAST(a.msrp AS DECIMAL)),0),0)::DECIMAL,2) AS discount, ROUND(CASE WHEN COUNT(*)!=0 THEN COUNT(CASE WHEN CAST(a.in_stock AS INTEGER)=1 THEN 1 ELSE NULL END)::FLOAT/COUNT(*) ELSE 0 END::DECIMAL,2) AS in_stock_perc FROM psm_ph_article_store psdm JOIN aid a ON psdm.article=a.article AND psdm.store_code=a.store_code JOIN ph ON ph.ph_code=psdm.ph_code GROUP BY 1), before_allocated AS (SELECT ph.ph_code, SUM(dp.eaches) AS eaches, SUM(dp.packs) AS packs FROM psm_ph_article_dc ph JOIN dc_pack dp ON dp.article=ph.article AND dp.dc_code=ph.dc_code GROUP BY 1), sda_agg AS (SELECT product_code, dc_code, size, article, SUM(COALESCE(oh,0)) AS oh, SUM(COALESCE(oo,0)) AS oo, SUM(COALESCE(it,0)) AS it FROM sku_dc_available GROUP BY 1,2,3,4), reserv_agg AS (SELECT product_code, dc_code, size, article, SUM(COALESCE(quantity,0)) AS quantity FROM sku_dc_reserved GROUP BY 1,2,3,4), alloc_agg AS (SELECT article, dc_code, size, MAX(updated_at) AS allocated_time, COALESCE(SUM(quantity),0) AS quantity FROM sku_dc_allocated GROUP BY 1,2,3), ladt_agg AS (SELECT article, allocated_time FROM last_allocated), inventory_details_product_dc AS (SELECT ph.product_code, ph.ph_code, ph.dc_code, ph.size, sda.oh, sda.oo, sda.it, COALESCE(sku_r.quantity,0) AS total_reserve, COALESCE(sdal.quantity,0) AS allocated_units, (sda.oh - COALESCE(sku_r.quantity,0) - COALESCE(sdal.quantity,0)) AS net_available_inventory, COALESCE(sdal.allocated_time, ladt.allocated_time, NULL) AS allocated_time FROM product_dc_map_after_store ph JOIN sda_agg sda USING (product_code, dc_code, size, article) LEFT JOIN reserv_agg sku_r USING (product_code, dc_code, size, article) LEFT JOIN alloc_agg sdal ON sdal.article=sda.article AND sdal.dc_code=sda.dc_code AND sdal.size=sda.size LEFT JOIN ladt_agg ladt ON ladt.article=sda.article), agg_inventory AS (SELECT product_code, ph_code, size, MAP(LIST(dc_code), LIST(oh)) AS oh_map, MAP(LIST(dc_code), LIST(allocated_units)) AS au_map, MAP(LIST(dc_code), LIST(total_reserve)) AS rq_map, SUM(oh) AS oh, SUM(oo) AS oo, SUM(it) AS it, SUM(total_reserve) AS reserve_quantity, SUM(net_available_inventory) AS net_available_inventory, SUM(allocated_units) AS allocated_units, MAX(allocated_time) AS allocated_time FROM inventory_details_product_dc GROUP BY 1,2,3), final_inventory AS (SELECT ph_code, to_json(MAP(LIST(size), LIST(oh_map))) AS oh_map, to_json(MAP(LIST(size), LIST(au_map))) AS au_map, to_json(MAP(LIST(size), LIST(rq_map))) AS rq_map, SUM(oh) AS oh, SUM(oo) AS oo, SUM(it) AS it, SUM(reserve_quantity) AS reserve_quantity, SUM(net_available_inventory) AS net_available_inventory, SUM(allocated_units) AS allocated_units, MAX(allocated_time) AS allocated_time FROM agg_inventory GROUP BY 1), constraint_data AS (SELECT ph_code, ROUND(AVG(aps)::NUMERIC,2) AS aps, ROUND(AVG(wos)::NUMERIC,2) AS wos, ROUND(AVG(min_stock)::NUMERIC,2) AS min_stock, ROUND(AVG(max_stock)::NUMERIC,2) AS max_stock, ROUND(MIN(max_stock)::NUMERIC,2) AS min_stock_validator, ROUND(MAX(min_stock)::NUMERIC,2) AS max_stock_validator, list(store_code) AS mapped_stores, len(list(store_code)) AS mapped_stores_count FROM (SELECT psm.ph_code, cm.store_code, SUM(cm.aps) AS aps, AVG(cm.wos) AS wos, AVG(cm.min_stock) AS min_stock, AVG(cm.max_stock) AS max_stock FROM rcl_constraints cm JOIN psm_ph_store psm USING (product_code, store_code) GROUP BY 1,2) foo GROUP BY 1), woc_data AS (SELECT ph_code, ROUND(AVG(woc)::NUMERIC,2) AS woc, ROUND(AVG(max_mod)::NUMERIC,2) AS avg_max_mod, ROUND(MIN(woc)::NUMERIC,2) AS min_woc, ROUND(MAX(woc)::NUMERIC,2) AS max_woc, COUNT(DISTINCT store_code) AS woc_mapped_stores_count FROM (SELECT psm.ph_code, psm.store_code, wm.woc, wm.max_mod FROM ph JOIN psm_ph_store psm ON psm.ph_code=ph.ph_code JOIN woc_master wm ON wm.l4_name=ph.l4_name AND wm.store_code=psm.store_code) woc_detail GROUP BY ph_code), product_profiles_ia AS (SELECT ph.ph_code, json_object(''value'', ppm.pp_code, ''name'', ppm.name, ''label'', ppm.special_classification) AS iapp FROM ph JOIN product_profile_master ppm ON ph.ph_code=ppm.ph_code WHERE ppm.special_classification=''ia-recommended''), article_dc_config AS (SELECT ph_code, list(DISTINCT json_object(''value'', dc.dc_code, ''label'', dc.name, ''is_default'', true)) AS dcs FROM product_store_dc_mapping JOIN distribution_centres dc USING (dc_code) GROUP BY 1), article_udpp_config AS (SELECT ph.ph_code, json_object(''value'', ppm.pp_code, ''name'', ppm.name, ''label'', ppm.special_classification) AS udpp FROM ph JOIN ph_configuration_mapping pcm USING (ph_code) JOIN product_profile_master ppm ON pcm.default_product_profile=ppm.pp_code JOIN pp_user_mapping_size ppums ON pcm.default_product_profile=ppums.pp_code), article_sg_config AS (SELECT pcm.ph_code, list(json_object(''value'', sg.sg_code, ''label'', sg.name, ''is_default'', true)) AS store_groups FROM (SELECT ph.ph_code, COALESCE(pcms.default_store_group, {default_sg_code}) AS default_sg_code FROM ph LEFT JOIN (SELECT ph_code, unnest(default_store_groups) AS default_store_group FROM ph_configuration_mapping) pcms USING (ph_code)) pcm JOIN store_groups sg ON pcm.default_sg_code=sg.sg_code GROUP BY 1), inventory_stock_stats AS (SELECT ph.ph_code, ROUND(CASE WHEN SUM(total_count)!=0 THEN CAST(SUM(in_stock_count) AS FLOAT)/CAST(SUM(total_count) AS FLOAT) ELSE 0 END::NUMERIC,4) AS in_stock_perc, ROUND(CASE WHEN SUM(dc_instock_total_count)!=0 THEN CAST(SUM(dc_instock_count) AS FLOAT)/CAST(SUM(dc_instock_total_count) AS FLOAT) ELSE 0 END::NUMERIC * 100,2) AS dc_instock FROM article_instock JOIN ph USING (article) GROUP BY 1), allocation_rule AS (SELECT pcm.ph_code, dspur.rule_code, dspur.values AS alloc_rules FROM ph_configuration_mapping pcm JOIN dc_store_policy_user_rule dspur ON pcm.dc_store_rule=dspur.rule_code) SELECT ph.l0_name, ph.l1_name, ph.l2_name, ph.l3_name, ph.l4_name, ph.l5_name, ph.style_color_description, ph.article, ph.ph_code, ph.product_description, ph.sizes, ph.product_codes AS upc, ph.product_lifecycle AS product_life_cycle, ph.article_status_tag, ph.brand, string_split(ph.channel, '','') AS channel, COALESCE(inv.reserve_quantity,0) AS reserve_quantity, COALESCE(inv.oh,0) AS oh, COALESCE(inv.oo,0) AS oo, COALESCE(inv.it,0) AS it, NULL AS pack_type_id, inv.oh_map, inv.rq_map, COALESCE(inv.allocated_units,0) AS allocated_units, (COALESCE(inv.oh,0)-COALESCE(inv.reserve_quantity,0)-COALESCE(inv.allocated_units,0)) AS net_available_inventory, inv.au_map, CASE WHEN ppu.udpp IS NULL THEN list_value(json_merge_patch(ppi.iapp, ''{\"is_default\": true}'')) WHEN ppi.iapp=ppu.udpp THEN list_value(json_merge_patch(ppi.iapp, ''{\"is_default\": true}'')) ELSE list_value(json_merge_patch(ppu.udpp, ''{\"is_default\": true}''), json_merge_patch(ppi.iapp, ''{\"is_default\": false}'')) END AS product_profiles, strftime(inv.allocated_time::TIMESTAMP, ''%m/%d/%Y'') AS last_allocated, adc.dcs, asgc.store_groups, cd.mapped_stores_count, cd.mapped_stores, cd.aps, CAST(ROUND(cd.min_stock) AS INTEGER) AS min_stock, CAST(ROUND(cd.max_stock) AS INTEGER) AS max_stock, CAST(ROUND(cd.min_stock_validator) AS INTEGER) AS min_stock_validator, CAST(ROUND(cd.max_stock_validator) AS INTEGER) AS max_stock_validator, CAST(ROUND(wd.woc) AS INTEGER) AS wos, CAST(ROUND(wd.avg_max_mod) AS INTEGER) AS avg_max_mod, CAST(ROUND(wd.min_woc) AS INTEGER) AS min_woc, CAST(ROUND(wd.max_woc) AS INTEGER) AS max_woc, tm.lw_units, tm.lw_margin, tm.lw_revenue, tm.price, tm.discount, iss.in_stock_perc, iss.dc_instock, COALESCE(ba.eaches,0) AS beginning_available_to_allocate_eaches, COALESCE(ba.packs,0) AS beginning_available_to_allocate_packs, ar.alloc_rules AS allocation_rules, COALESCE(ar.alloc_rules->>''min_type'', (SELECT values->>''min_type'' FROM dc_store_policy_user_rule WHERE rule_code=1 AND rule_type=''dc-store-rule'' LIMIT 1)) AS min_type FROM ph JOIN article_sg_config asgc ON ph.ph_code=asgc.ph_code LEFT JOIN final_inventory inv ON inv.ph_code=ph.ph_code JOIN constraint_data cd ON ph.ph_code=cd.ph_code LEFT JOIN woc_data wd ON ph.ph_code=wd.ph_code LEFT JOIN product_profiles_ia ppi ON ph.ph_code=ppi.ph_code JOIN article_dc_config adc ON ph.ph_code=adc.ph_code LEFT JOIN article_udpp_config ppu ON ph.ph_code=ppu.ph_code LEFT JOIN txs_metrics tm ON ph.ph_code=tm.ph_code LEFT JOIN inventory_stock_stats iss ON ph.ph_code=iss.ph_code LEFT JOIN before_allocated ba ON ba.ph_code=ph.ph_code LEFT JOIN allocation_rule ar ON ph.ph_code=ar.ph_code WHERE (COALESCE(inv.oh,0)-COALESCE(inv.reserve_quantity,0)-COALESCE(inv.allocated_units,0)) > 0"}, "children": []}, {"id": "get_partitions", "type": "duckdb_query", "label": "Get l1_name partitions", "config": {"depends_on": ["materialize"], "output_var": "partition_values", "query": "SELECT DISTINCT l1_name FROM article_selection_v2 ORDER BY 1"}, "children": []}, {"id": "write_partitions", "type": "loop", "label": "Write hive-partitioned parquet", "config": {"depends_on": ["materialize", "get_partitions"], "loop_over": "partition_values", "partition_col": "l1_name", "concurrency": 8, "output_path": "article_selection_v2"}, "children": [{"id": "write_part", "type": "duckdb_query", "label": "Write partition", "config": {"output_path": "article_selection_v2", "query": "SELECT * FROM article_selection_v2 WHERE l1_name = {partition_value}"}, "children": []}]}]}'),

  -- CASCADING_FILTERS
  json('[]')
);
